#include <stdio.h>
#include <errno.h>
#include <string.h>
#include <unistd.h>
ssize_t safe_write(int fd, const void *buf, size_t count) {
    ssize_t n;
    do {
        n = write(fd, buf, count);
    } while (n == -1 && errno == EINTR);
    return n;
}
int main(void) {
    int pipefd[2];
    pipe(pipefd);
    const char *msg = "safe write ok";
